// Load a background music file
StelAudioMgr.loadSound("/path/to/background.mp3", "bgMusic");

// Load a sound effect
StelAudioMgr.loadSound("/path/to/click.wav", "click");

// Reloading will replace the existing sound
StelAudioMgr.loadSound("/path/to/new_background.mp3", "bgMusic");

// Play background music
StelAudioMgr.playSound("bgMusic");

// Play a sound effect
StelAudioMgr.playSound("click");

// Restart from beginning if already playing
StelAudioMgr.playSound("alert");

// Check if sound exists before playing
var pos = StelAudioMgr.position("bgMusic");
if(pos >= 0) {
    StelAudioMgr.playSound("bgMusic");
}

// Pause background music
StelAudioMgr.pauseSound("bgMusic");

// Later, resume playback
StelAudioMgr.playSound("bgMusic");

// Stop background music
StelAudioMgr.stopSound("bgMusic");

// Will restart from the beginning
StelAudioMgr.playSound("bgMusic");

// Unload background music to free memory
StelAudioMgr.dropSound("bgMusic");

// Unload multiple sounds
StelAudioMgr.dropSound("click");
StelAudioMgr.dropSound("alert");

// Get and display current playback position
var pos = StelAudioMgr.position("bgMusic");
if(pos >= 0) {
    core.debug("Position: " + (pos/1000).toFixed(1) + " seconds");
} else {
    core.debug("Sound not loaded or cannot get position");
}

// Start playback, then get duration after a moment
StelAudioMgr.playSound("bgMusic");

// Wait a bit using a timer or delay
// ... 

var dur = StelAudioMgr.duration("bgMusic");
if(dur > 0) {
    core.debug("Total duration: " + (dur/1000).toFixed(1) + " seconds");
} else {
    core.debug("Duration unknown or sound not loaded");
}
